import{_ as a,o as t,c as n,a1 as o}from"./chunks/framework.BwbI10pK.js";const p=JSON.parse('{"title":"JavaScript Deep Dive","description":"","frontmatter":{},"headers":[],"relativePath":"en/javascript/index.md","filePath":"en/javascript/index.md"}'),i={name:"en/javascript/index.md"};function r(s,e,l,c,d,u){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="javascript-deep-dive" tabindex="-1">JavaScript Deep Dive <a class="header-anchor" href="#javascript-deep-dive" aria-label="Permalink to &quot;JavaScript Deep Dive&quot;">​</a></h1><blockquote><p>Subtitle: From execution context to the V8 engine, understand everything that truly happens at runtime.</p></blockquote><h2 id="module-positioning" tabindex="-1">Module Positioning <a class="header-anchor" href="#module-positioning" aria-label="Permalink to &quot;Module Positioning&quot;">​</a></h2><p>JavaScript is the language frontend engineers use every day, but there is a huge gap between &quot;can use it&quot; and &quot;understand it.&quot; This module does not stop at the syntax level. Instead, it goes deep into V8&#39;s execution mechanics: how execution contexts are created, how scope chains are formed, how closures persist in memory, how async tasks are scheduled in the event loop, how JIT optimizes hot code, and how GC reclaims memory.</p><p>Understanding these underlying mechanisms allows you to write code with predictable performance and to know where to start when investigating closure leaks, memory spikes, or long-task jank.</p><h2 id="core-topics" tabindex="-1">Core Topics <a class="header-anchor" href="#core-topics" aria-label="Permalink to &quot;Core Topics&quot;">​</a></h2><ul><li><strong>Execution mechanics</strong>: Execution context, scope chain, variable environment, lexical environment, and the nature of closures.</li><li><strong>Async programming</strong>: Event loop, macro/micro tasks, Promise chains, and the evolution and pitfalls of async/await.</li><li><strong>V8 engine</strong>: Ignition bytecode, Sparkplug / Maglev / TurboFan tiers, object shapes, and hidden classes.</li><li><strong>Memory management</strong>: Young / old generation GC, Scavenge and Mark-Sweep-Compact, short-lived objects, and memory leaks.</li><li><strong>Performance boundaries</strong>: JIT deoptimization, GC pauses, long-task splitting, and main-thread scheduling.</li></ul><h2 id="article-guide" tabindex="-1">Article Guide <a class="header-anchor" href="#article-guide" aria-label="Permalink to &quot;Article Guide&quot;">​</a></h2><ul><li><a href="/en/javascript/execution-context-closure">Execution Context &amp; Scope Chain</a> — Closures are not syntactic sugar; they are references held to lexical environments.</li><li><a href="/en/javascript/async-evolution">Async Programming Evolution</a> — The design thread and pitfalls of Promise / Generator / async/await.</li><li><a href="/en/javascript/v8-jit-gc">V8 Engine: JIT &amp; Garbage Collection</a> — From bytecode to TurboFan, from Scavenge to Mark-Compact.</li></ul><h2 id="intended-readers" tabindex="-1">Intended Readers <a class="header-anchor" href="#intended-readers" aria-label="Permalink to &quot;Intended Readers&quot;">​</a></h2><ul><li>Intermediate and senior frontend engineers who want to understand JavaScript runtime behavior rather than just syntax.</li><li>Performance engineers who need to troubleshoot memory leaks, long tasks, and JIT deoptimization.</li><li>Framework developers who need to evaluate the runtime cost and GC pressure of different APIs.</li></ul>',11)])])}const m=a(i,[["render",r]]);export{p as __pageData,m as default};
